func solve(matrix: Array<Array<Int64>>): Array<Int64> {
	n := len(matrix)
	ans := make([]Int64, n)

	for i := 0; i < n; i++ {
		var degree Int64 = 0
		for j := 0; j < n; j++ {
			// matrix[i][j] is 1 if connected, 0 otherwise.
			// Since the matrix is symmetric and matrix[i][i] = 0, 
			// summing the i-th row directly gives the degree.
			degree += matrix[i][j]
		}
		ans[i] = degree
	}

	return ans
}

